        <button onClick={onStart} style={{width:"100%",padding:14,borderRadius:T.rSm,fontSize:".9rem",fontWeight:600,cursor:"pointer",fontFamily:T.font,border:"none",transition:"all .25s",background:pl.hl?"linear-gradient(135deg,#3b82f6,#2563eb)":"transparent",color:pl.hl?"#fff":T.white,boxShadow:pl.hl?`0 4px 20px ${T.accentGlow}`:"none",...(!pl.hl?{border:`1.5px solid ${T.borderLight}`}:{})}}>Jetzt starten</button>
